rule.example:

class Something
{
    private int _q = 15; // VIOLATION - Field
    public void Main(int[] xs) // VIOLATION - Parameter
    {
        int r = 20; // VIOLATION - Local
        for (int i = 0; i < 10; i++) // Not a violation (for initializer)
        {
            r += _q;
        }
    }
}


class Something
{
    protected int _reallyLongIntName = -3; // VIOLATION - Field
    public void Main(int[] interestingArgumentsList) // VIOLATION - Parameter
    {
        int otherReallyLongName = -5; // VIOLATION - Local
    }
}


class ShortMethod
{
    public void A(int index) // Violation
    {
    }
}


class Foo
{
    const int MyNum = 0;    // ok (PascalCase)
    const string myTest = ""; // fail
}


class Foo
{
    public bool GetFoo() { return true; } // bad
    public bool IsFoo() { return true; }  // ok
    public bool GetFoo(int bar) { return true; } // ok unless checkParameterizedMethods=true
}
